import './index.less'
import { useState, useMemo, useEffect, useRef } from 'react'
import { useTranslation } from 'react-i18next'
import { Button, Input, Modal, Spin, Tree } from '@arco-design/web-react'
import { IconClose, IconDelete, IconLeft, IconRight, IconSearch, IconUpload } from '@arco-design/web-react/icon'
import { handelFieldNameShow } from '@/utils/tools'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'

interface Register {
  registerId: string
  registerName: string
  registerNameAr: string
  registerCode?: string | null
}

interface Activity {
  activityId: string
  activityName: string | null
  activityNameAr: string | null
  riskCount?: string | number
  registers?: Register[]
}

interface ProcessData {
  processId: string
  processName: string
  processNameAr?: string
  activities?: Activity[]
}

interface DualPanelRiskSelectorProps {
  visible: boolean
  onOk: (selectedRisks: Register[]) => void
  onCancel: () => void
  riskLibraryData: ProcessData[]
  loading?: boolean
}

const DualPanelRiskSelector = ({
  visible,
  onOk,
  onCancel,
  riskLibraryData = [],
  loading = false,
}: DualPanelRiskSelectorProps) => {
  const { t } = useTranslation(['risk', 'common'])
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const [keyword, setKeyword] = useState('')
  const [checkedKeys, setCheckedKeys] = useState<string[]>([])
  const [selectedList, setSelectedList] = useState<Register[]>([])
  const [expandedKeys, setExpandedKeys] = useState<string[]>([])
  console.log('riskLibraryData', riskLibraryData)

  const selectedIds = useMemo(
    () => new Set(selectedList.map((r) => r.registerId)),
    [selectedList],
  )

  const registerMap = useMemo(() => {
    const map = new Map<string, Register>()
    for (const process of riskLibraryData) {
      for (const activity of process.activities || []) {
        for (const register of activity.registers || []) {
          map.set(register.registerId, register)
        }
      }
    }
    return map
  }, [riskLibraryData])

  const fullTreeData = useMemo(() => {
    return riskLibraryData.map((process) => ({
      title: handelFieldNameShow(process.processName, process.processNameAr) || '-',
      key: `process_${process.processId}`,
      selectable: false,
      checkable: false,
      children: (process.activities || []).map((activity) => {
        const activityTitle =
          handelFieldNameShow(activity.activityName, activity.activityNameAr) || '-'
        const countSuffix =
          activity.riskCount !== undefined ? ` (${activity.riskCount})` : ''
        return {
          title: activityTitle + countSuffix,
          key: `activity_${activity.activityId}`,
          selectable: false,
          checkable: false,
          children: (activity.registers || []).map((register) => ({
            title: handelFieldNameShow(register.registerName, register.registerNameAr) || '-',
            key: `register_${register.registerId}`,
            isLeaf: true,
            disabled: selectedIds.has(register.registerId),
          })),
        }
      }),
    }))
  }, [riskLibraryData, selectedIds])

  const filteredTreeData = useMemo(() => {
    if (!keyword.trim()) return fullTreeData

    const kw = keyword.trim().toLowerCase()

    const filterNode = (node: any): any => {
      if (node.isLeaf) {
        const registerId = node.key.replace('register_', '')
        const reg = registerMap.get(registerId)
        if (!reg) return null
        const matches =
          (reg.registerName || '').toLowerCase().includes(kw) ||
          (reg.registerNameAr || '').toLowerCase().includes(kw)
        return matches ? node : null
      }
      const filteredChildren = (node.children || []).map(filterNode).filter(Boolean)
      if (filteredChildren.length === 0) return null
      return { ...node, children: filteredChildren }
    }

    return fullTreeData.map(filterNode).filter(Boolean)
  }, [fullTreeData, keyword, registerMap])

  const filteredTreeDataRef = useRef<any[]>([])
  filteredTreeDataRef.current = filteredTreeData

  useEffect(() => {
    const processKeys = riskLibraryData.map((p) => `process_${p.processId}`)
    setExpandedKeys(processKeys)
  }, [riskLibraryData])

  // Only re-run when keyword changes — NOT when filteredTreeData changes due to selection
  useEffect(() => {
    if (!keyword.trim()) {
      setExpandedKeys(riskLibraryData.map((p) => `process_${p.processId}`))
      return
    }
    const collectKeys = (nodes: any[]): string[] =>
      nodes.flatMap((node) =>
        node.isLeaf ? [] : [node.key, ...collectKeys(node.children || [])],
      )
    setExpandedKeys(collectKeys(filteredTreeDataRef.current))
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [keyword, riskLibraryData])

  const handleCheck = (keys: any) => {
    const checkedArr: string[] = Array.isArray(keys)
      ? keys
      : (keys as { checked: string[] }).checked || []
    setCheckedKeys(checkedArr.filter((k) => k.startsWith('register_')))
  }

  const handleMoveToRight = () => {
    const newItems: Register[] = []
    for (const key of checkedKeys) {
      const registerId = key.replace('register_', '')
      if (!selectedIds.has(registerId)) {
        const register = registerMap.get(registerId)
        if (register) newItems.push(register)
      }
    }
    if (newItems.length > 0) {
      setSelectedList((prev) => [...prev, ...newItems])
    }
    setCheckedKeys([])
  }

  const removeItem = (registerId: string) => {
    setSelectedList((prev) => prev.filter((r) => r.registerId !== registerId))
  }

  const handleCancel = () => {
    setKeyword('')
    setCheckedKeys([])
    setSelectedList([])
    onCancel()
  }

  const handleOk = () => {
    onOk(selectedList)
    setKeyword('')
    setCheckedKeys([])
    setSelectedList([])
  }

  return (
    <Modal
      title={t('risk:addExistingRisk')}
      visible={visible}
      onCancel={handleCancel}
      autoFocus={false}
      focusLock={false}
      style={{ width: 800 }}
      footer={
        <div className='dual-panel-footer'>
          <Button icon={<IconClose />} onClick={handleCancel}>
            {t('common:btn.cancel')}
          </Button>
          <Button
            type='primary'
            icon={<IconUpload style={{ fill: '#fff' }} />}
            disabled={selectedList.length === 0}
            onClick={handleOk}
          >
            {t('common:btn.confirm')} ({selectedList.length})
          </Button>
        </div>
      }
    >
      <div className='dual-panel-body'>
        {/* Left: tree with checkboxes */}
        <div className='dual-panel-left'>
          <Input
            prefix={<IconSearch />}
            placeholder={t('risk:searchRisk')}
            value={keyword}
            onChange={(v) => setKeyword(v)}
            allowClear
            style={{ marginBottom: 8 }}
          />
          <div className='dual-panel-list'>
            <Spin loading={loading}>
              {filteredTreeData.length === 0 && !loading ? (
                <div className='dual-panel-empty'>-</div>
              ) : (
                <Tree
                  treeData={filteredTreeData}
                  checkable
                  checkStrictly
                  checkedKeys={checkedKeys}
                  onCheck={handleCheck}
                  expandedKeys={expandedKeys}
                  onExpand={(keys) => setExpandedKeys(keys as string[])}
                  selectedKeys={[]}
                  blockNode
                />
              )}
            </Spin>
          </div>
        </div>

        {/* Center: move button */}
        <div className='dual-panel-center' onClick={handleMoveToRight}>
          <div className='dual-panel-center-btn'>
            {isLanguageAR ? <IconLeft /> : <IconRight />}
          </div>
        </div>

        {/* Right: confirmed selection */}
        <div className='dual-panel-right'>
          <div className='dual-panel-right-header'>
            <span>{t('risk:selected')} ({selectedList.length})</span>
            {selectedList.length > 0 && (
              <IconDelete
                className='dual-panel-clear-icon'
                onClick={() => setSelectedList([])}
              />
            )}
          </div>
          <div className='dual-panel-list'>
            {selectedList.length === 0 ? (
              <div className='dual-panel-empty'>-</div>
            ) : (
              selectedList.map((item) => {
                const name = handelFieldNameShow(item.registerName, item.registerNameAr)
                return (
                  <div key={item.registerId} className='dual-panel-item'>
                    <span className='dual-panel-item-name'>{name}</span>
                    <IconClose
                      className='dual-panel-item-remove'
                      onClick={() => removeItem(item.registerId)}
                    />
                  </div>
                )
              })
            )}
          </div>
        </div>
      </div>
    </Modal>
  )
}

export default DualPanelRiskSelector

