import { useState } from 'react'
import { Button, Input, List, Message, Modal, Spin, Tag } from '@arco-design/web-react'
import { IconClose, IconSearch } from '@arco-design/web-react/icon'
import { useRequest } from 'ahooks'
import { useTranslation } from 'react-i18next'
import { getEnterpriseRiskListSorted, linkExistingEnterpriseRisk } from '@/service/apis/risk'
import { handelFieldNameShow } from '@/utils/tools'

interface EnterpriseRisk {
  enterpriseRiskId: string
  name: string
  nameAr?: string
  categoryName?: string
  categoryNameAr?: string
}

interface SearchAndLinkModalProps {
  visible: boolean
  riskId: string
  currentRiskName?: string
  currentRiskDescription?: string
  currentCategoryId?: string
  onSuccess: () => void
  onCancel: () => void
}

const SearchAndLinkModal = ({
  visible,
  riskId,
  currentRiskName,
  currentRiskDescription,
  currentCategoryId,
  onSuccess,
  onCancel,
}: SearchAndLinkModalProps) => {
  const { t } = useTranslation(['risk', 'common'])
  const [keyword, setKeyword] = useState('')
  const [selectedId, setSelectedId] = useState<string | null>(null)

  const { data, loading } = useRequest(
    () =>
      getEnterpriseRiskListSorted({
        riskId,
        name: currentRiskName,
        description: currentRiskDescription,
        categoryId: currentCategoryId,
      }),
    {
      ready: visible,
      refreshDeps: [visible],
      onError: () => {},
    },
  )

  const riskList: EnterpriseRisk[] = (data as any)?.data || []

  const filtered = keyword.trim()
    ? riskList.filter((r) => {
        const kw = keyword.toLowerCase()
        return (
          (r.name || '').toLowerCase().includes(kw) ||
          (r.nameAr || '').toLowerCase().includes(kw)
        )
      })
    : riskList

  const { run: doLink, loading: linking } = useRequest(linkExistingEnterpriseRisk, {
    manual: true,
    onSuccess: () => {
      Message.success(t('risk:linkSuccess'))
      onSuccess()
      handleClose()
    },
  })

  const handleClose = () => {
    setKeyword('')
    setSelectedId(null)
    onCancel()
  }

  const handleOk = () => {
    if (!selectedId) return
    doLink({ riskId, enterpriseRiskId: selectedId })
  }

  return (
    <Modal
      title={t('risk:addExistingEnterpriseRisk')}
      visible={visible}
      onCancel={handleClose}
      autoFocus={false}
      focusLock={false}
      style={{ width: 560 }}
      footer={
        <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 8 }}>
          <Button icon={<IconClose />} onClick={handleClose}>
            {t('common:btn.cancel')}
          </Button>
          <Button
            type='primary'
            disabled={!selectedId}
            loading={linking}
            onClick={handleOk}
          >
            {t('common:btn.confirm')}
          </Button>
        </div>
      }
    >
      <Input
        prefix={<IconSearch />}
        placeholder={t('common:search')}
        value={keyword}
        onChange={(v) => setKeyword(v)}
        allowClear
        style={{ marginBottom: 12 }}
      />
      <div style={{ height: 360, overflowY: 'auto' }}>
        <Spin loading={loading}>
          {filtered.length === 0 && !loading ? (
            <div style={{ textAlign: 'center', color: '#86909C', paddingTop: 60 }}>-</div>
          ) : (
            <List
              dataSource={filtered}
              render={(item: EnterpriseRisk, index) => (
                <List.Item
                  key={item.enterpriseRiskId}
                  style={{
                    cursor: 'pointer',
                    background: selectedId === item.enterpriseRiskId ? '#E8F3FF' : undefined,
                    borderRadius: 4,
                    padding: '8px 12px',
                    marginBottom: 4,
                  }}
                  onClick={() => setSelectedId(item.enterpriseRiskId)}
                >
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    {index < 3 && (
                      <Tag color='arcoblue' size='small'>
                        {t('risk:recommendedTag')}
                      </Tag>
                    )}
                    <span>{handelFieldNameShow(item.name, item.nameAr)}</span>
                    {item.categoryName && (
                      <Tag size='small'>
                        {handelFieldNameShow(item.categoryName, item.categoryNameAr)}
                      </Tag>
                    )}
                  </div>
                </List.Item>
              )}
            />
          )}
        </Spin>
      </div>
    </Modal>
  )
}

export default SearchAndLinkModal
```

