import { useEffect, useState } from 'react'
import {
  Button,
  Form,
  Input,
  List,
  Message,
  Modal,
  Select,
  Spin,
  Tag,
} from '@arco-design/web-react'
import { IconClose, IconUpload } from '@arco-design/web-react/icon'
import { useRequest } from 'ahooks'
import { useTranslation } from 'react-i18next'
import { getEnterpriseRiskListSorted, submitRiskProposal } from '@/service/apis/risk'
import { handelFieldNameShow } from '@/utils/tools'

interface EnterpriseRisk {
  enterpriseRiskId: string
  name: string
  nameAr?: string
}

interface ProposeRiskModalProps {
  visible: boolean
  riskId: string
  categoryOptions?: { value: string; label: string }[]
  onSuccess: () => void
  onCancel: () => void
}

const FormItem = Form.Item
const TextArea = Input.TextArea

const ProposeRiskModal = ({
  visible,
  riskId,
  categoryOptions = [],
  onSuccess,
  onCancel,
}: ProposeRiskModalProps) => {
  const { t } = useTranslation(['risk', 'common'])
  const [form] = Form.useForm()
  const [selectedEnterpriseId, setSelectedEnterpriseId] = useState<string | null>(null)
  const [sortedList, setSortedList] = useState<EnterpriseRisk[]>([])

  const { run: fetchSortedList, loading: listLoading } = useRequest(
    getEnterpriseRiskListSorted,
    {
      manual: true,
      onSuccess: (res: any) => setSortedList(res?.data || []),
      onError: () => {},
    },
  )

  useEffect(() => {
    if (visible) {
      const values = form.getFieldsValue()
      fetchSortedList({
        riskId,
        name: values.name,
        description: values.description,
        categoryId: values.categoryId,
      })
    }
  }, [visible])

  const { run: doSubmit, loading: submitting } = useRequest(submitRiskProposal, {
    manual: true,
    onSuccess: () => {
      Message.success(t('risk:proposalSubmitSuccess'))
      onSuccess()
      handleClose()
    },
  })

  const handleClose = () => {
    form.resetFields()
    setSelectedEnterpriseId(null)
    setSortedList([])
    onCancel()
  }

  const handleOk = () => {
    form.validate().then((values) => {
      doSubmit({
        riskId,
        name: values.name,
        nameAr: values.nameAr || undefined,
        description: values.description || undefined,
        descriptionAr: values.descriptionAr || undefined,
        categoryId: values.categoryId || undefined,
        enterpriseRiskId: selectedEnterpriseId || undefined,
      })
    })
  }

  // 表单内容变化时刷新推荐列表
  const handleFormChange = () => {
    const values = form.getFieldsValue()
    if (values.name || values.description) {
      fetchSortedList({
        riskId,
        name: values.name,
        description: values.description,
        categoryId: values.categoryId,
      })
    }
  }

  return (
    <Modal
      title={t('risk:proposeNewEnterpriseRisk')}
      visible={visible}
      onCancel={handleClose}
      autoFocus={false}
      focusLock={false}
      style={{ width: 720 }}
      footer={
        <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 8 }}>
          <Button icon={<IconClose />} onClick={handleClose}>
            {t('common:btn.cancel')}
          </Button>
          <Button
            type='primary'
            icon={<IconUpload style={{ fill: '#fff' }} />}
            loading={submitting}
            onClick={handleOk}
          >
            {t('common:btn.confirm')}
          </Button>
        </div>
      }
    >
      <div style={{ display: 'flex', gap: 16 }}>
        {/* 左侧：填写表单 */}
        <div style={{ flex: 1 }}>
          <Form form={form} layout='vertical' onChange={handleFormChange}>
            <FormItem
              field='name'
              label={t('risk:proposalRiskName')}
              rules={[{ required: true, message: t('common:required') }]}
            >
              <Input maxLength={500} placeholder={t('common:pleaseEnter')} />
            </FormItem>
            <FormItem field='nameAr' label={t('risk:proposalRiskNameAr')}>
              <Input maxLength={500} dir='rtl' placeholder={t('common:pleaseEnter')} />
            </FormItem>
            <FormItem field='categoryId' label={t('risk:form1.riskCategory')}>
              <Select options={categoryOptions} placeholder={t('common:pleaseSelect')} allowClear />
            </FormItem>
            <FormItem field='description' label={t('risk:proposalDescription')}>
              <TextArea rows={3} maxLength={2000} showWordLimit placeholder={t('common:pleaseEnter')} />
            </FormItem>
            <FormItem field='descriptionAr' label={t('risk:proposalDescriptionAr')}>
              <TextArea rows={3} maxLength={2000} showWordLimit dir='rtl' placeholder={t('common:pleaseEnter')} />
            </FormItem>
          </Form>
        </div>

        {/* 右侧：相似度推荐 */}
        <div style={{ width: 280, flexShrink: 0 }}>
          <div style={{ marginBottom: 8, fontWeight: 500 }}>
            {t('risk:selectEnterpriseRisk')}
          </div>
          <div style={{ height: 360, overflowY: 'auto', border: '1px solid #E5E6EB', borderRadius: 4, padding: '4px 0' }}>
            <Spin loading={listLoading}>
              {sortedList.length === 0 && !listLoading ? (
                <div style={{ textAlign: 'center', color: '#86909C', paddingTop: 40 }}>-</div>
              ) : (
                <List
                  dataSource={sortedList}
                  render={(item: EnterpriseRisk, index) => (
                    <List.Item
                      key={item.enterpriseRiskId}
                      style={{
                        cursor: 'pointer',
                        background:
                          selectedEnterpriseId === item.enterpriseRiskId ? '#E8F3FF' : undefined,
                        borderRadius: 4,
                        padding: '6px 12px',
                      }}
                      onClick={() =>
                        setSelectedEnterpriseId(
                          selectedEnterpriseId === item.enterpriseRiskId
                            ? null
                            : item.enterpriseRiskId,
                        )
                      }
                    >
                      <div style={{ display: 'flex', alignItems: 'center', gap: 6, flexWrap: 'wrap' }}>
                        {index < 3 && (
                          <Tag color='arcoblue' size='small'>
                            {t('risk:recommendedTag')}
                          </Tag>
                        )}
                        <span style={{ fontSize: 13 }}>
                          {handelFieldNameShow(item.name, item.nameAr)}
                        </span>
                      </div>
                    </List.Item>
                  )}
                />
              )}
            </Spin>
          </div>
          {selectedEnterpriseId && (
            <div style={{ marginTop: 6, fontSize: 12, color: '#4E5969' }}>
              ✓ {sortedList.find((r) => r.enterpriseRiskId === selectedEnterpriseId)
                ? handelFieldNameShow(
                    sortedList.find((r) => r.enterpriseRiskId === selectedEnterpriseId)!.name,
                    sortedList.find((r) => r.enterpriseRiskId === selectedEnterpriseId)!.nameAr,
                  )
                : ''}
            </div>
          )}
        </div>
      </div>
    </Modal>
  )
}

export default ProposeRiskModal
