import './index.less'
import { useState } from 'react'
import { Button, Collapse, Message, Spin, Tag, Tooltip } from '@arco-design/web-react'
import { IconPlus } from '@arco-design/web-react/icon'
import { useTranslation } from 'react-i18next'
import { useRequest } from 'ahooks'
import { handelFieldNameShow } from '@/utils/tools'
import SearchAndLinkModal from './components/SearchAndLinkModal'
import ProposeRiskModal from './components/ProposeRiskModal'

interface LinkedRisk {
  enterpriseRiskId?: string
  proposalId?: string
  name: string
  nameAr?: string
  /** 0=待审批 1=已审批 2=已拒绝 99=直接关联（无提案） */
  status: number
  rejectReason?: string
}

interface EnterpriseRiskLinkingSectionProps {
  riskId: string
  detailData?: any
  categoryOptions?: { value: string; label: string }[]
  onRefresh?: () => void
}

const statusClassMap: Record<number, string> = {
  0: 'status-pending',
  1: 'status-approved',
  2: 'status-rejected',
  99: 'status-linked',
}

const CollapseItem = Collapse.Item

const EnterpriseRiskLinkingSection = ({
  riskId,
  detailData,
  categoryOptions = [],
  onRefresh,
}: EnterpriseRiskLinkingSectionProps) => {
  const { t } = useTranslation(['risk', 'common'])
  const [searchModalVisible, setSearchModalVisible] = useState(false)
  const [proposeModalVisible, setProposeModalVisible] = useState(false)

  // 已关联列表来自父组件 detailData，实际结构由后端返回字段决定
  const linkedRisks: LinkedRisk[] = detailData?.enterpriseRisks || []

  const handleSuccess = () => {
    onRefresh?.()
  }

  return (
    <div className='enterprise-risk-linking'>
      <Collapse className='common-collapse' expandIconPosition='right' defaultActiveKey={['enterpriseRiskLinking']}>
        <CollapseItem
          header={t('risk:enterpriseRiskLinking')}
          name='enterpriseRiskLinking'
        >
          {/* 已关联风险列表 */}
          {linkedRisks.length === 0 ? (
            <div style={{ color: '#86909C', marginBottom: 12, fontSize: 13 }}>
              {t('risk:noLinkedRisks')}
            </div>
          ) : (
            <div className='linked-risk-list'>
              {linkedRisks.map((risk, i) => {
                const name = handelFieldNameShow(risk.name, risk.nameAr)
                const statusKey = String(risk.status) as keyof typeof t
                const statusLabel = t(`risk:proposalStatus.${risk.status}`)
                const className = statusClassMap[risk.status] ?? 'status-linked'
                return (
                  <Tooltip
                    key={risk.proposalId ?? risk.enterpriseRiskId ?? i}
                    content={risk.status === 2 ? risk.rejectReason : undefined}
                    disabled={risk.status !== 2}
                  >
                    <span className={`linked-risk-tag ${className}`}>
                      {name}
                      <Tag size='small' style={{ marginLeft: 4 }} color={risk.status === 1 ? 'green' : risk.status === 0 ? 'orange' : 'red'}>
                        {statusLabel}
                      </Tag>
                    </span>
                  </Tooltip>
                )
              })}
            </div>
          )}

          {/* 操作按钮 */}
          <div className='action-btns'>
            <Button
              icon={<IconPlus />}
              size='small'
              onClick={() => setSearchModalVisible(true)}
            >
              {t('risk:addExistingEnterpriseRisk')}
            </Button>
            <Button
              icon={<IconPlus />}
              size='small'
              onClick={() => setProposeModalVisible(true)}
            >
              {t('risk:proposeNewEnterpriseRisk')}
            </Button>
          </div>
        </CollapseItem>
      </Collapse>

      <SearchAndLinkModal
        visible={searchModalVisible}
        riskId={riskId}
        currentRiskName={detailData?.riskName}
        currentRiskDescription={detailData?.riskDescription}
        currentCategoryId={detailData?.riskCategoryId}
        onSuccess={handleSuccess}
        onCancel={() => setSearchModalVisible(false)}
      />

      <ProposeRiskModal
        visible={proposeModalVisible}
        riskId={riskId}
        categoryOptions={categoryOptions}
        onSuccess={handleSuccess}
        onCancel={() => setProposeModalVisible(false)}
      />
    </div>
  )
}

export default EnterpriseRiskLinkingSection
