// 建议直接内联在 Approvals/index.tsx，或抽为单独文件
// src/pages/Governance/Approvals/components/ProposalRiskApprovalList/index.tsx

import { useState } from 'react'
import { Button, Form, Input, List, Modal, Popconfirm, Tag } from '@arco-design/web-react'
import { useRequest } from 'ahooks'
import { useTranslation } from 'react-i18next'
import {
  approveRiskProposal,
  getRiskProposalList,
  rejectRiskProposal,
} from '@/service/apis/risk'
import { handelFieldNameShow } from '@/utils/tools'

interface ProposalRisk {
  proposalId: string
  name: string
  nameAr?: string
  description?: string
  status: number
  rejectReason?: string
}

interface ProposalRiskApprovalListProps {
  recordId: string
}

const FormItem = Form.Item

const ProposalRiskApprovalList = ({ recordId }: ProposalRiskApprovalListProps) => {
  const { t } = useTranslation(['risk', 'common'])
  const [rejectModalVisible, setRejectModalVisible] = useState(false)
  const [rejectForm] = Form.useForm()
  const [currentProposalId, setCurrentProposalId] = useState<string | null>(null)

  const { data, loading, refresh } = useRequest(
    () => getRiskProposalList({ recordId, status: 0 }),
    {
      ready: !!recordId,
      refreshDeps: [recordId],
    },
  )

  const proposals: ProposalRisk[] = (data as any)?.data || []

  const { run: doApprove, loading: approving } = useRequest(approveRiskProposal, {
    manual: true,
    onSuccess: () => { refresh() },
  })

  const { run: doReject, loading: rejecting } = useRequest(rejectRiskProposal, {
    manual: true,
    onSuccess: () => {
      setRejectModalVisible(false)
      rejectForm.resetFields()
      refresh()
    },
  })

  const openRejectModal = (proposalId: string) => {
    setCurrentProposalId(proposalId)
    setRejectModalVisible(true)
  }

  const handleRejectSubmit = () => {
    rejectForm.validate().then((values) => {
      if (!currentProposalId) return
      doReject({ proposalId: currentProposalId, rejectReason: values.rejectReason })
    })
  }

  if (proposals.length === 0 && !loading) return null

  return (
    <div style={{ marginTop: 16 }}>
      <div style={{ fontWeight: 500, marginBottom: 8 }}>{t('risk:proposalRisks')}</div>
      <List
        loading={loading}
        dataSource={proposals}
        render={(item: ProposalRisk) => (
          <List.Item
            key={item.proposalId}
            actions={[
              <Popconfirm
                key='approve'
                title={t('common:confirmApprove')}
                onOk={() => doApprove({ proposalId: item.proposalId })}
              >
                <Button size='small' type='primary' loading={approving}>
                  {t('common:btn.approve')}
                </Button>
              </Popconfirm>,
              <Button
                key='reject'
                size='small'
                status='danger'
                onClick={() => openRejectModal(item.proposalId)}
              >
                {t('common:btn.reject')}
              </Button>,
            ]}
          >
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <span>{handelFieldNameShow(item.name, item.nameAr)}</span>
              <Tag color='orange' size='small'>{t('risk:proposalStatus.0')}</Tag>
            </div>
          </List.Item>
        )}
      />

      <Modal
        title={t('common:btn.reject')}
        visible={rejectModalVisible}
        onOk={handleRejectSubmit}
        onCancel={() => { setRejectModalVisible(false); rejectForm.resetFields() }}
        confirmLoading={rejecting}
      >
        <Form form={rejectForm} layout='vertical'>
          <FormItem
            field='rejectReason'
            label={t('risk:rejectReason')}
            rules={[{ required: true, message: t('risk:rejectReasonRequired') }]}
          >
            <Input.TextArea rows={4} maxLength={1000} showWordLimit />
          </FormItem>
        </Form>
      </Modal>
    </div>
  )
}

export default ProposalRiskApprovalList
```

